exercises.solution:
function divideAsync(a, b, callback) {
  return new Promise(resolve => {
    if (b === 0) {
      callback(new Error('Cannot divide by zero'), null);
    } else {
      callback(null, a / b);
    }
    resolve();
  });
}

await divideAsync(10, 2, function(err, result) {
  if (err) {
    console.log('Error:', err.message);
    return;
  }
  console.log('Result:', result);
});

await divideAsync(5, 0, function(err, result) {
  if (err) {
    console.log('Error:', err.message);
    return;
  }
  console.log('Result:', result);
});

